-- BigQuery style pseudocode 
-- 1) Top-level per-minute queue depth + avg queue time by region/model 
SELECT minute_ts, region, model_family, count(*) AS queued_requests, avg(queue_ms) AS avg_queue_ms, percentile_cont(queue_ms, 0.9) AS p90_queue_ms FROM scheduler.request_queue_metrics_v2 WHERE minute_ts BETWEEN '2026-10-04 00:00:00' AND '2026-10-08 23:59:59' AND queue_ms > 100 GROUP BY minute_ts, region, model_family ORDER BY minute_ts;

-- 2) KV cache pressure: per-minute misses vs hits and mem pressure (MB) by region/model 
SELECT minute_ts, region, model_family, sum(kv_hits) AS kv_hits, sum(kv_misses) AS kv_misses, avg(kv_mem_mb) AS avg_kv_mem_mb FROM runtime.kv_cache_events WHERE minute_ts BETWEEN '2026-10-04' AND '2026-10-08' GROUP BY minute_ts, region, model_family;

-- 3) Join queue depth with kv metrics and token-length buckets (short/medium/long) 
SELECT q.minute_ts, q.region, q.model_family, q.queued_requests, q.avg_queue_ms, k.kv_hits, k.kv_misses, k.avg_kv_mem_mb, t.len_bucket, t.count AS requests_in_bucket FROM ( /* query 1 */ ) q LEFT JOIN ( /* query 2 */ ) k ON q.minute_ts = k.minute_ts AND q.region = k.region AND q.model_family = k.model_family LEFT JOIN (SELECT minute_ts, region, model_family, CASE WHEN total_tokens < 64 THEN 'short' WHEN total_tokens < 512 THEN 'medium' ELSE 'long' END AS len_bucket, count(*) AS count FROM request.token_stream_stats WHERE minute_ts BETWEEN '2026-10-04' AND '2026-10-08' GROUP BY minute_ts, region, model_family, len_bucket) t ON q.minute_ts = t.minute_ts AND q.region = t.region AND q.model_family = t.model_family;
